export const getPhase1Problems = () => problems.filter(p => p.phase === 1);
export const getPhase2Problems = () => problems.filter(p => p.phase === 2);
export const getProblemsByWeek = (week: number) => problems.filter(p => p.week === week);
export const getProblemsByTopic = (topic: string) => problems.filter(p => p.topic === topic);
export const getTotalProblems = () => problems.length;
